const original = String($json.chatInput ?? '').trim();
if (!original) {
  throw new Error('No chat input found');
}

const promptGovernance = $json._openbox ?? { governed: false };
const promptWallOutput = String($json.output ?? $json.text ?? '').trim();
const lower = original.toLowerCase();
const has = (...terms) => terms.some((term) => lower.includes(term));

const severity = has('outage', 'down', 'breach', 'security', 'suspicious login', 'verified and secured', 'cannot login', 'cannot pay')
  ? 'high'
  : has('refund', 'chargeback', 'duplicate charge', 'cancel', 'invoice')
    ? 'medium'
    : 'normal';

const route = has('breach', 'security', 'suspicious login', 'verified and secured', 'password', 'token')
  ? 'security-review'
  : has('refund', 'chargeback', 'duplicate charge')
    ? 'billing-ops'
    : has('invoice', 'pay', 'payment', 'cannot pay')
      ? 'revenue-ops'
      : 'support-queue';

const needsHumanReview = severity === 'high' || route === 'security-review' || route === 'billing-ops';
const customerId = has('acme', 'invoice', 'payment', 'cannot pay') ? 3 : has('refund', 'duplicate charge', 'chargeback') ? 5 : 2;
const accountTier = severity === 'high' ? 'enterprise' : route === 'billing-ops' ? 'business' : 'starter';
const ticketId = 'N8N-' + Date.now().toString().slice(-6);

return {
  json: {
    ...$json,
    originalChatInput: original,
    promptGovernance,
    promptWallOutput,
    ticket: {
      id: ticketId,
      severity,
      route,
      needsHumanReview,
      customerId,
      accountTier,
      source: 'n8n-chat'
    }
  }
};

const ticketInput = $('Prepare Ticket Context').item.json;
const row = $json;
const customerContext = {
  id: row.customer_id,
  name: row.name,
  email: row.email,
  company: row.company,
  city: row.city,
  website: row.website,
  accountTier: row.account_tier,
  riskNote: row.risk_note,
  lookupSource: row.lookup_source ?? 'postgres-demo.customers'
};

const contextTripwire = ticketInput.originalChatInput.toLowerCase().includes('contextblock') ? 'Demo context checkpoint tripwire: blockme' : '';

const governedPrompt = [
  'Prepare an internal support triage packet for the following customer issue.',
  '',
  'Ticket ID: ' + ticketInput.ticket.id,
  'Customer: ' + customerContext.name + ' (' + customerContext.company + ')',
  'Account tier: ' + customerContext.accountTier,
  'Customer lookup source: ' + customerContext.lookupSource,
  'Customer city: ' + customerContext.city,
  'Account risk note: ' + customerContext.riskNote,
  'Original customer message: ' + ticketInput.originalChatInput,
  'Initial severity: ' + ticketInput.ticket.severity,
  'Suggested route: ' + ticketInput.ticket.route,
  'Human review required: ' + (ticketInput.ticket.needsHumanReview ? 'yes' : 'no'),
  contextTripwire,
  '',
  'Return concise sections: Summary, Customer Reply Draft, Internal Next Step, Risks.',
  'Do not claim the account was changed, refunded, paid, cancelled, or verified unless the provided customer context says so.'
].join('\n');

return {
  json: {
    ...ticketInput,
    customer: customerContext,
    chatInput: governedPrompt
  }
};

const ticket = $json.ticket ?? {};
const customer = $json.customer ?? {};
const governance = $json.draftGovernance ?? $json._openbox ?? { governed: false };
const llmDraft = String($json.llmDraft ?? $json.output ?? $json.text ?? '').trim();
const review = ticket.needsHumanReview ? 'human-review-required' : 'auto-reply-candidate';
const summary = 'Ticket ' + ticket.id + ' -> ' + ticket.route + ' (' + ticket.severity + ')';
const slackEnabled = true;
const hubspotEnabled = Boolean($env.HUBSPOT_CRM_ENABLED === 'true');
const clip = (value, max = 2800) => String(value ?? '').slice(0, max);
const slackEscape = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');
const field = (label, value) => ({
  type: 'mrkdwn',
  text: '*' + label + '*\n' + slackEscape(value || 'unknown')
});

const notificationText = [
  '*' + summary + '*',
  'Customer: ' + (customer.name ?? 'unknown') + ' / ' + (customer.company ?? 'unknown company') + ' / ' + (customer.accountTier ?? 'unknown tier'),
  'Review: ' + review,
  'OpenBox draft: ' + (governance.governed ? 'governed' : 'not governed'),
  '',
  llmDraft.slice(0, 1400)
].join('\n');

const slackBlocks = {
  blocks: [
    {
      type: 'header',
      text: {
        type: 'plain_text',
        text: 'OpenBox triage: ' + (ticket.id ?? 'new ticket'),
        emoji: true
      }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: '*' + slackEscape(ticket.route ?? 'support-queue') + '* route · *' + slackEscape(ticket.severity ?? 'normal') + '* severity · *' + slackEscape(review) + '*'
      }
    },
    {
      type: 'section',
      fields: [
        field('Customer', (customer.name ?? 'unknown') + ' / ' + (customer.company ?? 'unknown company')),
        field('Tier', customer.accountTier ?? 'unknown'),
        field('Lookup', customer.lookupSource ?? 'postgres-demo.customers'),
        field('OpenBox draft', governance.governed ? 'governed' : 'not governed')
      ]
    },
    { type: 'divider' },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: '*Customer message*\n>' + slackEscape(clip($json.originalChatInput ?? '', 900)).replace(/\n/g, '\n>')
      }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: '*Governed draft excerpt*\n' + slackEscape(clip(llmDraft || 'No draft returned.', 1800))
      }
    },
    {
      type: 'context',
      elements: [
        {
          type: 'mrkdwn',
          text: 'OpenBox checks passed before Slack delivery · backend log: demo.triage_events'
        }
      ]
    }
  ]
};

const crmMessage = [
  summary,
  'Customer: ' + (customer.name ?? 'unknown') + ' / ' + (customer.company ?? 'unknown company'),
  'Review: ' + review,
  '',
  llmDraft.slice(0, 2000)
].join('\n');

const channelPayloads = {
  chat: { text: notificationText },
  slack: {
    enabled: slackEnabled,
    channelId: $env.SLACK_CHANNEL_ID ?? '',
    text: notificationText,
    blocks: slackBlocks
  },
  hubspot: {
    enabled: hubspotEnabled,
    email: customer.email ?? '',
    firstName: String(customer.name ?? '').split(' ')[0] || 'Demo',
    lastName: String(customer.name ?? '').split(' ').slice(1).join(' ') || 'Customer',
    companyName: customer.company ?? '',
    websiteUrl: customer.website ?? '',
    city: customer.city ?? '',
    message: crmMessage,
    leadStatus: ticket.needsHumanReview ? 'OPEN' : 'NEW',
    lifeCycleStage: ticket.severity === 'high' ? 'customer' : 'lead'
  },
  backend: {
    enabled: true,
    table: 'demo.triage_events'
  }
};

const channelTripwire = String($json.originalChatInput ?? '').toLowerCase().includes('channelblock') ? 'Demo channel checkpoint tripwire: blockme' : '';

const channelAuditPrompt = [
  'Review these outbound channel payloads before delivery.',
  'Slack enabled: ' + channelPayloads.slack.enabled,
  'Slack format: Block Kit blocks with fallback notification text',
  'HubSpot CRM enabled: ' + channelPayloads.hubspot.enabled,
  'Backend event log enabled: true',
  'Chat excerpt: ' + channelPayloads.chat.text.slice(0, 900),
  channelTripwire,
  'Do not approve payloads that leak secrets, unnecessary PII, NSFW content, or unapproved account/payment/refund/security actions.'
].join('\n');

return {
  json: {
    ...$json,
    channelPayloads,
    chatInput: channelAuditPrompt
  }
};

const ticket = $json.ticket ?? {};
const customer = $json.customer ?? {};
const promptGovernance = $json.promptGovernance ?? { governed: false };
const contextGovernance = $json.contextGovernance ?? { governed: false };
const draftGovernance = $json.draftGovernance ?? { governed: false };
const channelGovernance = $json.channelGovernance ?? { governed: false };
const llmDraft = String($json.llmDraft ?? '').trim();
const review = ticket.needsHumanReview ? 'human-review-required' : 'auto-reply-candidate';
const promptPre = promptGovernance.pre ?? {};
const promptPost = promptGovernance.post ?? {};
const contextPre = contextGovernance.pre ?? {};
const contextPost = contextGovernance.post ?? {};
const draftPre = draftGovernance.pre ?? {};
const draftPost = draftGovernance.post ?? {};
const channelPre = channelGovernance.pre ?? {};
const channelPost = channelGovernance.post ?? {};
const riskyPatterns = [
  /payment is now complete/i,
  /account (was|has been) (changed|reset|verified|cancelled|canceled|refunded)/i,
  /refund (was|has been|is now)/i,
  /insert contact details/i,
  /legal commitment/i
];
const riskFlags = riskyPatterns.filter((pattern) => pattern.test(llmDraft)).map((pattern) => pattern.source);
const requiresApproval = review === 'human-review-required' || riskFlags.length > 0;
const safeReplyDraft = [
  'Thanks for flagging this. We have routed ticket ' + ticket.id + ' to ' + ticket.route + ' with ' + ticket.severity + ' priority.',
  'A support specialist will review the account context before confirming any account, billing, payment, refund, or security action.',
  'We will follow up with the next verified step once the review is complete.'
].join(' ');
const summary = (meta, pre, post) => {
  if (!meta.governed) return 'not governed';
  const preText = pre.arm ? pre.arm + (pre.riskScore !== undefined ? ' (' + pre.riskScore + ')' : '') : 'not reported';
  const postText = post.arm ? post.arm + (post.riskScore !== undefined ? ' (' + post.riskScore + ')' : '') : 'not reported';
  return 'governed | input ' + preText + ' | output ' + postText;
};

const packet = {
  ticketId: ticket.id,
  severity: ticket.severity,
  route: ticket.route,
  review,
  requiresApproval,
  riskFlags,
  customer,
  checks: {
    promptWall: {
      summary: summary(promptGovernance, promptPre, promptPost),
      classifierOutput: $json.promptWallOutput
    },
    contextPrivacy: {
      summary: summary(contextGovernance, contextPre, contextPost),
      classifierOutput: $json.contextCheckOutput
    },
    draftGovernance: {
      summary: summary(draftGovernance, draftPre, draftPost)
    },
    channelOutput: {
      summary: summary(channelGovernance, channelPre, channelPost),
      classifierOutput: $json.channelCheckOutput
    }
  },
  channels: {
    chat: 'sent',
    slack: 'attempted-nonblocking',
    hubspot: $json.channelPayloads?.hubspot?.enabled ? 'configured' : 'skipped-missing-HUBSPOT_CRM_ENABLED',
    backend: 'recorded-to-Postgres'
  },
  customerMessage: $json.originalChatInput,
  safeReplyDraft,
  llmDraftStatus: requiresApproval ? 'held-for-review' : 'ready-for-review',
  llmDraftExcerpt: llmDraft.slice(0, 900)
};

const response = [
  'Ticket ' + packet.ticketId + ' -> ' + packet.route + ' (' + packet.severity + ')',
  'Customer: ' + (customer.name ?? 'unknown') + ' / ' + (customer.company ?? 'unknown company') + ' / ' + (customer.accountTier ?? 'unknown tier'),
  'Customer lookup: ' + (customer.lookupSource ?? 'unknown'),
  'OpenBox checks:',
  '1. Prompt safety wall: ' + packet.checks.promptWall.summary,
  '2. Context privacy check: ' + packet.checks.contextPrivacy.summary,
  '3. Draft governance: ' + packet.checks.draftGovernance.summary,
  '4. Channel output check: ' + packet.checks.channelOutput.summary,
  'Review: ' + packet.review,
  'Actions: chat sent; Slack ' + packet.channels.slack + '; HubSpot ' + packet.channels.hubspot + '; backend ' + packet.channels.backend,
  '',
  'Safe customer reply draft:',
  packet.safeReplyDraft,
  '',
  requiresApproval
    ? 'LLM draft status: held for reviewer approval before any customer-facing use.'
    : 'LLM draft status: ready for reviewer approval.',
  riskFlags.length ? 'Risk flags: ' + riskFlags.length : 'Risk flags: none'
].join('\n');

return {
  json: {
    ...$json,
    packet,
    route: packet.route,
    review: packet.review,
    output: response,
    text: response
  }
};

return {
  json: {
    ...$json,
    contextGovernance: $json._openbox ?? { governed: false },
    contextCheckOutput: String($json.output ?? $json.text ?? '').trim()
  }
};

return {
  json: {
    ...$json,
    draftGovernance: $json._openbox ?? { governed: false },
    llmDraft: String($json.output ?? $json.text ?? '').trim()
  }
};

return {
  json: {
    ...$json,
    channelGovernance: $json._openbox ?? { governed: false },
    channelCheckOutput: String($json.output ?? $json.text ?? '').trim()
  }
};

const raw = String($json.originalChatInput ?? $json.chatInput ?? $json.text ?? $json.event?.text ?? '').trim();
const openbox = $json._openbox ?? {};
const ticket = $json.ticket ?? {};
const customer = $json.customer ?? {};
const checkpoint = openbox.nodeName ?? 'OpenBox checkpoint';
const stage = openbox.blockStage ?? ($json.error ? 'node-error' : 'unknown');
const reason = openbox.blockReason ?? $json.error?.message ?? $json.error ?? 'OpenBox stopped this workflow step';
const ticketId = ticket.id ?? ('N8N-OPENBOX-' + Date.now().toString().slice(-6));
const route = 'blocked-by-openbox';
const severity = ticket.severity ?? 'blocked';
const review = 'terminal-output-after-openbox-block';
const slackEscape = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');
const stopLine = checkpoint === 'OpenBox: Prompt Safety Wall'
  ? 'This request was stopped before customer lookup, enrichment, drafting, or external business actions.'
  : 'This execution stopped business actions at this checkpoint, then emitted terminal outputs.';
const response = [
  'Ticket ' + ticketId + ' -> ' + route + ' (' + severity + ')',
  'OpenBox terminal output:',
  'Checkpoint: ' + checkpoint,
  'Stage: ' + stage,
  'Reason: ' + reason,
  'Review: ' + review,
  'Actions: chat sent; Slack attempted-nonblocking; HubSpot skipped-until-safe; backend recorded-to-Postgres',
  '',
  stopLine
].join('\n');
const slackBlocks = {
  blocks: [
    {
      type: 'header',
      text: { type: 'plain_text', text: 'OpenBox blocked: ' + ticketId, emoji: true }
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: '*Checkpoint*\n' + slackEscape(checkpoint) }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: '*Stage*\n' + slackEscape(stage) },
        { type: 'mrkdwn', text: '*Severity*\n' + slackEscape(severity) },
        { type: 'mrkdwn', text: '*Review*\n' + slackEscape(review) },
        { type: 'mrkdwn', text: '*Route*\n' + slackEscape(route) }
      ]
    },
    { type: 'divider' },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: '*Reason*\n' + slackEscape(reason).slice(0, 1800) }
    },
    {
      type: 'context',
      elements: [{ type: 'mrkdwn', text: slackEscape(stopLine) + ' · backend log: demo.triage_events' }]
    }
  ]
};
return {
  json: {
    ...$json,
    ticket: { ...ticket, id: ticketId, route, severity },
    packet: {
      ticketId,
      route,
      severity,
      review,
      customer,
      customerMessage: raw,
      checks: {
        openboxTerminal: {
          checkpoint,
          stage,
          reason,
          governed: Boolean(openbox.governed),
          runId: openbox.runId,
          workflowId: openbox.workflowId
        }
      },
      channels: { chat: 'sent', slack: 'attempted-nonblocking', hubspot: 'skipped-until-safe', backend: 'recorded-to-Postgres' }
    },
    route,
    review,
    channelPayloads: { slack: { channelId: $env.SLACK_CHANNEL_ID ?? '', text: response, blocks: slackBlocks } },
    output: response,
    text: response
  }
};

const packet = $json.packet ?? {};
const ticket = $json.ticket ?? {};
const openbox = $json._openbox ?? {};
const channelPayloads = $json.channelPayloads ?? {};
const source = $json.inputSource ?? ticket.source ?? 'n8n-chat';
const terminal = packet.checks?.openboxTerminal;
const normalChecks = packet.checks ?? {};
const pathLog = [];

pathLog.push({ step: 'input', source, result: 'received' });
pathLog.push({ step: 'slack-input', result: source === 'slack-agent' ? 'used' : 'not-used' });
pathLog.push({ step: 'prompt-wall', result: terminal?.checkpoint === 'OpenBox: Prompt Safety Wall' ? 'blocked' : 'passed', detail: normalChecks.promptWall?.summary ?? terminal?.reason ?? null });
pathLog.push({ step: 'customer-lookup', result: terminal?.checkpoint === 'OpenBox: Prompt Safety Wall' ? 'skipped' : 'completed', detail: $json.customer?.lookupSource ?? null });
pathLog.push({ step: 'context-check', result: terminal?.checkpoint === 'OpenBox: Context Privacy Check' ? 'blocked' : (normalChecks.contextPrivacy ? 'passed' : 'skipped'), detail: normalChecks.contextPrivacy?.summary ?? null });
pathLog.push({ step: 'draft-governance', result: terminal?.checkpoint === 'OpenBox: Governed LLM Draft' ? 'blocked' : (normalChecks.draftGovernance ? 'passed' : 'skipped'), detail: normalChecks.draftGovernance?.summary ?? null });
pathLog.push({ step: 'channel-check', result: terminal?.checkpoint === 'OpenBox: Channel Output Check' ? 'blocked' : (normalChecks.channelOutput ? 'passed' : 'skipped'), detail: normalChecks.channelOutput?.summary ?? null });
pathLog.push({ step: 'review-package', result: packet.review ? 'built' : 'terminal-built', detail: packet.review ?? null });
pathLog.push({ step: 'chat-output', result: 'queued' });
pathLog.push({ step: 'slack-output', result: 'attempted-nonblocking', detail: channelPayloads.slack?.channelId ? 'channel-configured' : 'missing-channel-or-placeholder-credential' });
pathLog.push({ step: 'hubspot-output', result: channelPayloads.hubspot?.enabled ? 'configured-for-attempt' : 'skipped-not-enabled', detail: channelPayloads.hubspot?.enabled ? 'HUBSPOT_CRM_ENABLED=true' : 'HUBSPOT_CRM_ENABLED!=true' });
pathLog.push({ step: 'backend-final-log', result: 'recording' });

const finalLog = {
  ticketId: packet.ticketId ?? ticket.id ?? 'unknown',
  route: packet.route ?? ticket.route ?? 'unknown',
  severity: packet.severity ?? ticket.severity ?? 'unknown',
  review: packet.review ?? $json.review ?? 'unknown',
  source,
  terminal: terminal ?? null,
  channels: {
    chat: 'sent',
    slack: 'attempted-nonblocking',
    hubspot: channelPayloads.hubspot?.enabled ? 'configured-for-attempt' : 'skipped-not-enabled',
    backend: 'recorded-to-Postgres'
  },
  pathLog,
  openbox: {
    currentNode: openbox.nodeName ?? null,
    blocked: Boolean(openbox.blocked),
    blockStage: openbox.blockStage ?? null,
    blockReason: openbox.blockReason ?? null,
    runId: openbox.runId ?? null,
    workflowId: openbox.workflowId ?? null
  },
  packet
};

const slackEscape = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');
const clip = (value, max = 900) => String(value ?? '').trim().replace(/\s+/g, ' ').slice(0, max);
const status = terminal ? 'blocked' : 'allowed';
const title = terminal ? 'OpenBox blocked: ' + finalLog.ticketId : 'OpenBox triage: ' + finalLog.ticketId;
const customer = packet.customer ?? $json.customer ?? {};
const checkSteps = ['prompt-wall', 'customer-lookup', 'context-check', 'draft-governance', 'channel-check'];
const checksText = pathLog
  .filter((entry) => checkSteps.includes(entry.step))
  .map((entry) => '- ' + entry.step + ': ' + entry.result)
  .join('\n');
const customerLine = [customer.name, customer.company, customer.accountTier].filter(Boolean).join(' / ') || 'unknown';
const customerMessage = packet.customerMessage ?? $json.originalChatInput ?? $json.chatInput ?? '';
const resultText = terminal
  ? ['*Checkpoint:* ' + slackEscape(terminal.checkpoint ?? 'OpenBox checkpoint'), '*Stage:* ' + slackEscape(terminal.stage ?? 'unknown'), '*Reason:* ' + slackEscape(clip(terminal.reason, 900))].join('\n')
  : ['*Safe reply draft:*', slackEscape(clip(packet.safeReplyDraft ?? 'A support specialist will review and follow up with the next verified step.', 900))].join('\n');
const slackText = [
  title,
  'Status: ' + status,
  'Route: ' + finalLog.route,
  'Severity: ' + finalLog.severity,
  'Review: ' + finalLog.review
].join('\n');
const statusLabel = status === 'allowed' ? 'ALLOWED' : 'BLOCKED';
const statusLine = statusLabel + ' | ' + String(finalLog.route).toUpperCase() + ' | ' + String(finalLog.severity).toUpperCase();
const fieldText = (label, value) => ({
  type: 'mrkdwn',
  text: '*' + label + '*\n' + slackEscape(value || 'unknown')
});
const resultSummary = terminal
  ? '*Checkpoint*\n' + slackEscape(terminal.checkpoint ?? 'OpenBox checkpoint') + '\n\n*Reason*\n' + slackEscape(clip(terminal.reason, 900))
  : '*Safe reply draft*\n' + slackEscape(clip(packet.safeReplyDraft ?? 'A support specialist will review and follow up with the next verified step.', 900));
const checksFields = pathLog
  .filter((entry) => checkSteps.includes(entry.step))
  .map((entry) => fieldText(entry.step, entry.result));
const slackBlocks = {
  blocks: [
    {
      type: 'header',
      text: { type: 'plain_text', text: title.slice(0, 150), emoji: false }
    },
    {
      type: 'context',
      elements: [
        { type: 'mrkdwn', text: '`' + slackEscape(statusLine) + '`' },
        { type: 'mrkdwn', text: '*Review:* ' + slackEscape(finalLog.review) }
      ]
    },
    { type: 'divider' },
    {
      type: 'section',
      fields: [
        fieldText('Customer', customerLine),
        fieldText('Source', source),
        fieldText('Lookup', customer.lookupSource ?? 'not-run'),
        fieldText('Backend log', 'demo.triage_events')
      ]
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: '*Customer message*\n>' + slackEscape(clip(customerMessage, 900)) }
    },
    { type: 'divider' },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: '*OpenBox result*\n' + resultSummary }
    },
    {
      type: 'section',
      fields: checksFields
    },
    {
      type: 'actions',
      elements: (() => {
        const actionValue = (approvalStage, decision) => JSON.stringify({ ticketId: finalLog.ticketId, route: finalLog.route, severity: finalLog.severity, review: finalLog.review, approvalStage, decision });
        const button = (text, actionId, value, style) => ({
          type: 'button',
          text: { type: 'plain_text', text, emoji: false },
          ...(style ? { style } : {}),
          value,
          action_id: actionId
        });
        const openWorkflow = {
          type: 'button',
          text: { type: 'plain_text', text: 'Open n8n workflow', emoji: false },
          url: 'http://localhost:5678/workflow/aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',
          action_id: 'open_n8n_workflow'
        };
        if (terminal?.checkpoint === 'OpenBox: Prompt Safety Wall') {
          return [
            button('Mark false positive', 'openbox_prompt_false_positive', actionValue('prompt-wall', 'false-positive'), 'primary'),
            button('Keep blocked', 'openbox_prompt_keep_blocked', actionValue('prompt-wall', 'kept-blocked'), 'danger'),
            openWorkflow
          ];
        }
        if (terminal?.checkpoint === 'OpenBox: Channel Output Check') {
          return [
            button('Approve send', 'openbox_send_approve', actionValue('channel-output', 'approved'), 'primary'),
            button('Reject send', 'openbox_send_reject', actionValue('channel-output', 'rejected'), 'danger'),
            button('Request rewrite', 'openbox_send_rewrite', actionValue('channel-output', 'rewrite-requested')),
            openWorkflow
          ];
        }
        return [
          button('Approve draft', 'openbox_draft_approve', actionValue('draft-governance', 'approved'), 'primary'),
          button('Reject draft', 'openbox_draft_reject', actionValue('draft-governance', 'rejected'), 'danger'),
          button('Approve send', 'openbox_send_approve', actionValue('channel-output', 'approved')),
          openWorkflow
        ];
      })()
    },    {
      type: 'context',
      elements: [{ type: 'mrkdwn', text: 'OpenBox governed support triage. Stage-specific approvals post to the Slack actions webhook.' }]
    }
  ]
};
const nextChannelPayloads = {
  ...channelPayloads,
  slack: {
    ...(channelPayloads.slack ?? {}),
    text: slackText,
    blocks: slackBlocks
  }
};

return {
  json: {
    ...$json,
    channelPayloads: nextChannelPayloads,
    pathLog,
    finalLog,
    packet: {
      ...packet,
      pathLog,
      finalLog
    }
  }
};

const source = $('Build Final Log').item.json;
const text = source.channelPayloads?.chat?.text || source.output || source.text || 'Workflow completed. Check Slack and demo.triage_events for details.';
return { json: { text, output: text, response: text } };

const body = $json.body ?? $json;
const rawPayload = body.payload ?? $json.payload ?? '';
const payload = typeof rawPayload === 'string' ? JSON.parse(rawPayload) : rawPayload;
const action = payload.actions?.[0] ?? {};
const actionValue = action.value ? JSON.parse(action.value) : {};
const approvalStage = actionValue.approvalStage ?? (action.action_id?.includes('prompt') ? 'prompt-wall' : action.action_id?.includes('send') ? 'channel-output' : 'draft-governance');
